import{_ as o,o as a,c as d,a2 as i}from"./chunks/framework.C90q7Ucc.js";const g=JSON.parse('{"title":"排障指南","description":"","frontmatter":{},"headers":[],"relativePath":"guide/troubleshooting.md","filePath":"guide/troubleshooting.md","lastUpdated":1780839435000}'),s={name:"guide/troubleshooting.md"};function l(t,e,c,r,n,p){return a(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="排障指南" tabindex="-1">排障指南 <a class="header-anchor" href="#排障指南" aria-label="Permalink to &quot;排障指南&quot;">​</a></h1><p>本文合并排障步骤和常见问题。遇到问题时，先确认本地 bridge 是否运行，再区分是飞书长连接收不到事件、runtime 没有输出，还是 CardKit 刷新失败。</p><h2 id="桥接服务无法启动" tabindex="-1">桥接服务无法启动 <a class="header-anchor" href="#桥接服务无法启动" aria-label="Permalink to &quot;桥接服务无法启动&quot;">​</a></h2><p><strong>现象</strong>：从本地工作台启动 bridge 失败，或者 daemon 启动后立即退出。</p><p><strong>排查步骤</strong>：</p><ol><li>运行本地 doctor 脚本，或查看工作台日志定位问题。</li><li>确认已安装 Node.js 24+：<code>node --version</code>。</li><li>确认 Codex CLI 可用：<code>codex --version</code>。</li><li>确认配置文件存在：<code>ls -la ~/.codelark/config.toml</code>。</li><li>查看 <code>~/.codelark/logs/</code> 下的启动错误日志。</li></ol><p><strong>常见原因</strong>：</p><ul><li><code>config.toml</code> 缺失或内容无效。打开本地工作台并保存一份有效配置；旧版 <code>config.json</code> / <code>config.env</code> 会在启动迁移后归档。</li><li>Node.js 未安装或版本不正确。安装 Node.js 24+。</li><li>端口或资源冲突。检查是否已有另一个 bridge 实例正在运行。</li><li>bridge 实例已经死亡，但是 PID 文件仍然存在。可以先尝试 <code>codelark stop</code>，仍失败时手动删除 <code>~/.codelark/runtime/bridge.pid</code> 后重新启动。</li></ul><h3 id="codelark-run-后-bridge-启动失败" tabindex="-1"><code>codelark run</code> 后 bridge 启动失败 <a class="header-anchor" href="#codelark-run-后-bridge-启动失败" aria-label="Permalink to &quot;`codelark run` 后 bridge 启动失败&quot;">​</a></h3><p>先查看：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codelark</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p>再打开工作台日志页，确认飞书凭据、Codex / Claude Code 登录态和本机 Node.js 版本。日志目录通常在：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.codelark/logs/</span></span></code></pre></div><h2 id="收不到消息" tabindex="-1">收不到消息 <a class="header-anchor" href="#收不到消息" aria-label="Permalink to &quot;收不到消息&quot;">​</a></h2><p><strong>现象</strong>：bot 在线，但不会回复消息。</p><p><strong>排查步骤</strong>：</p><ol><li>查看 <code>~/.codelark/logs/bridge.log</code> 中最近的 JSONL 日志；优先筛选 <code>level</code> 为 <code>ERROR</code> 或 <code>WARN</code>，再看 <code>msg</code> 里是否有 <code>ws client</code> 或 WebSocket 连接错误。如果有，说明 bridge 没有连上飞书长连接服务器。</li><li>查看 <code>~/.codelark/logs/bridge.log</code> 中是否有 bot OpenID 相关日志；如果没有获取到，通常是 bot 配置有误，可以用 <code>codelark setup</code> 重新配置。</li><li>查看 <code>~/.codelark/logs/bridge.log</code> 中是否有消息事件日志；结构化日志可重点看 <code>event</code>、<code>channel</code>、<code>chat</code>、<code>message</code>、<code>msg</code> 字段。如果没有，很可能是飞书 bot 没有添加对应事件回调，或当前应用版本还未发布/审批生效。到飞书开发者后台添加事件与回调后重新发布应用。</li><li>如果是在群聊中，尝试 @bot 发送消息，确认是否可以正常回复。<code>@bot /require-at off</code> 之后就不必须 @bot。</li><li>检查配置中的 allowed user IDs。如果已设置，只有列表中的用户可以交互。</li></ol><h3 id="飞书配置检查清单" tabindex="-1">飞书配置检查清单 <a class="header-anchor" href="#飞书配置检查清单" aria-label="Permalink to &quot;飞书配置检查清单&quot;">​</a></h3><ul><li>飞书应用是否已发布并审批。</li><li>Bot 能力是否已启用。</li><li>长连接事件订阅是否保存成功。</li><li><code>im.message.receive_v1</code>、<code>drive.notice.comment_add_v1</code>、<code>im.chat.member.bot.deleted_v1</code>、<code>im.chat.disbanded_v1</code> 是否已添加。</li><li><code>card.action.trigger</code> 回调是否已添加。</li><li>云文档评论回复是否缺少 <code>docs:document.comment:create</code> 或 <code>docs:document.comment:write_only</code> 权限。</li><li>bridge 是否正在运行。</li></ul><h2 id="权限或用户限制不符合预期" tabindex="-1">权限或用户限制不符合预期 <a class="header-anchor" href="#权限或用户限制不符合预期" aria-label="Permalink to &quot;权限或用户限制不符合预期&quot;">​</a></h2><p>默认 <code>CODELARK_FEISHU_ALLOWED_USERS=</code> 为空，表示不做用户白名单限制。要限制用户，设置为飞书 open_id 列表：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CODELARK_FEISHU_ALLOWED_USERS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ou_xxx,ou_yyy</span></span></code></pre></div><p>修改后重启 bridge：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codelark</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codelark</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span></code></pre></div><p>如果用户在白名单内仍无法交互，优先检查日志里识别到的 open_id 是否和配置一致。飞书 user id、union id、open_id 不是同一个值。</p><h2 id="很久没有回复-流式卡片很久没有更新" tabindex="-1">很久没有回复/流式卡片很久没有更新 <a class="header-anchor" href="#很久没有回复-流式卡片很久没有更新" aria-label="Permalink to &quot;很久没有回复/流式卡片很久没有更新&quot;">​</a></h2><ul><li>群聊如果太多，先尝试解散不再使用的群聊并重启 bridge。</li><li>如果不是 <code>yolo</code> mode，可能是 agent 卡在权限确认上。可以先用 <code>/</code> 查看当前 mode，再按任务风险决定是否用 <code>/mode yolo</code> 或 <code>/m yolo</code> 切换。</li><li>如果当前是 tmux/pty provider 路径，可以使用 <code>/tmux-screen</code> 或 <code>/pty-screen</code> 查看终端状态；Claude Code 默认 tmux 路径用 <code>/tmux-screen</code>。</li><li>如果卡片已经进入终态但没有追加新的纯文本消息，先看卡片上是否已有最终内容和终态 reaction；当前实现会在最终更新失败但已有卡片内容时保留卡片，避免重复发送 fallback 文本。</li></ul><h2 id="飞书流式卡片不可用" tabindex="-1">飞书流式卡片不可用 <a class="header-anchor" href="#飞书流式卡片不可用" aria-label="Permalink to &quot;飞书流式卡片不可用&quot;">​</a></h2><p><strong>现象</strong>：飞书只收到最终普通消息，或者已经开启流式卡片但卡片没有出现。</p><p><strong>排查步骤</strong>：</p><ol><li>查看 <code>~/.codelark/logs/bridge.log</code>；日志是一行一条 JSON 的结构化 JSONL。</li><li>搜索飞书错误 <code>99991672</code>，或筛选 <code>level=ERROR/WARN</code> 后查看 <code>msg</code> 和飞书响应字段。</li><li>如果错误提到 <code>cardkit:card:write</code>、<code>cardkit:card:read</code> 或 <code>im:message:update</code>，补充对应权限并发布新版本。</li><li>新版本审批通过后，重启 bridge。</li></ol><p>即使权限正确，Codex SDK 也通常不是逐字 token 流；飞书流式卡片主要展示 thinking、工具进度和最终答案更新。</p><h3 id="流式卡片没有逐字输出" tabindex="-1">流式卡片没有逐字输出 <a class="header-anchor" href="#流式卡片没有逐字输出" aria-label="Permalink to &quot;流式卡片没有逐字输出&quot;">​</a></h3><p>这是当前预期行为。飞书卡片的 <code>streaming_mode</code> 控制 CardKit 打字机展示效果，但 CodeLark 的主要投递机制是本地 desired state 合并、投递计划和 CardKit 刷新。当前 Codex SDK 事件通常在 assistant 消息完成时给出最终文本，所以用户更常看到 thinking、工具进度、状态和最终答案阶段性更新，而不是 token-by-token 输出。</p><p>如果卡片完全不更新，再看 <code>~/.codelark/logs/bridge.log</code> 中这些日志：</p><ul><li><code>Streaming sync plan</code></li><li><code>cardElement.content:*</code></li><li><code>card.batchUpdate:*</code></li><li><code>card.update:streaming_refresh</code></li><li><code>Streaming card perf summary</code></li></ul><h2 id="命令被当成-slash-命令" tabindex="-1">命令被当成 slash 命令 <a class="header-anchor" href="#命令被当成-slash-命令" aria-label="Permalink to &quot;命令被当成 slash 命令&quot;">​</a></h2><p>发送以 <code>/</code> 开头的普通文本时，在前面多加一个 <code>/</code>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>//status</span></span></code></pre></div><p>这会把 <code>/status</code> 作为普通消息发给 Codex / Claude Code，而不是执行 CodeLark 命令。</p><h2 id="本地会话找不到" tabindex="-1">本地会话找不到 <a class="header-anchor" href="#本地会话找不到" aria-label="Permalink to &quot;本地会话找不到&quot;">​</a></h2><p><code>/t</code> 依赖本机 runtime 会话索引。排查顺序：</p><ol><li>确认当前 runtime 是否正确：<code>/runtime codex</code> 或 <code>/runtime claude</code>。</li><li>确认 provider 是否符合预期：<code>/provider sdk</code>、<code>/provider pty</code> 或 <code>/provider tmux</code>。</li><li>在本机确认 Codex / Claude Code 已经产生过会话。</li><li>在工作台查看本地会话列表和 bridge 日志。</li></ol><p>如果本机路径是符号链接，CodeLark 会尽量同时识别原始路径和 realpath；仍找不到时，把 <code>/status</code> 和相关日志一起用于排查。</p><h2 id="云文档评论无法回复" tabindex="-1">云文档评论无法回复 <a class="header-anchor" href="#云文档评论无法回复" aria-label="Permalink to &quot;云文档评论无法回复&quot;">​</a></h2><p>能收到 <code>drive.notice.comment_add_v1</code> 事件但不能写回评论时，通常是权限问题。检查：</p><ul><li>飞书控制台是否添加 <code>docs:document.comment:read</code>。</li><li>是否添加 <code>docs:document.comment:create</code>。</li><li>是否添加 <code>docs:document.comment:write_only</code>。</li><li>新权限是否已经重新发布并审批。</li><li>bridge 是否在审批后重启。</li></ul><p>云文档转群聊还可能依赖 user auth scope。使用工作台或 setup 重新检查 <code>lark-cli</code> 登录和授权状态。</p><h2 id="卸载和清理" tabindex="-1">卸载和清理 <a class="header-anchor" href="#卸载和清理" aria-label="Permalink to &quot;卸载和清理&quot;">​</a></h2><p>停止 bridge：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codelark</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span></code></pre></div><p>如需清理 CodeLark 本地数据，再删除：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.codelark</span></span></code></pre></div><p>删除 <code>~/.codelark</code> 会移除配置、聊天绑定、会话缓存、日志和运行状态；不会删除 Codex / Claude Code 自己的会话数据。</p>',54)])])}const u=o(s,[["render",l]]);export{g as __pageData,u as default};
